VALUES
  ('locality-7c9828ae-moex-00105', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '甲依法申請補助，主管機關逾法定處理期間仍未作成准駁之處分，甲乃於處理期間屆至後提起訴願，該機 關於甲提起訴願後始作成否准處分，並送達於甲。依司法實務見解，受理訴願機關應如何處理甲之訴願？', '["應逕以該否准處分為標的續行審理甲之訴願", "因怠為處分與否准處分屬不同之標的，應定期間命甲確答訴願請求為何", "應逕以甲之訴願不合法定要件，依訴願法第77條作成不受理決定", "因該機關已作出處分，故應依法作成訴願無理由駁回之實體決定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00106', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '依訴願法規定，訴願提起之期間，為下列何者？', '["10日", "15日", "20日", "30日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00107', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於訴願代理人之敘述，下列何者錯誤？', '["每一訴願人委任之訴願代理人不得超過3人", "訴願代理人有2人以上者，應共同代理", "與訴願人有親屬關係者，得擔任訴願代理人", "訴願代理人就其受委任之事件，如受特別委任，得撤回訴願"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00108', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '甲因申請應用檔案，不服國家發展委員會檔案管理局之駁回決定，提起訴願時，該事件訴願管轄機關 為何？', '["行政院", "行政院訴願審議委員會", "國家發展委員會檔案管理局", "國家發展委員會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00109', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於行政執行之敘述，下列何者錯誤？', '["行政執行應以適當之方法為之，不得逾越達成執行目的之必要程度", "行政執行，自處分確定之日起，5年內未經執行者，不再執行", "行政執行之終止，僅得由執行機關依職權為之", "行政執行原則上不得於夜間、星期日或其他休息日為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00110', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於行政訴訟之管轄，下列敘述何者錯誤？', '["因不動產徵收之訴訟，專屬於不動產所在地之行政法院管轄", "關於公務員職務關係之訴訟，得由公務員職務所在地之行政法院管轄", "因公法上之保險事件涉訟者，得由為原告之受益人住居所地之行政法院管轄", "定行政法院之管轄以言詞辯論時為準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00111', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '依行政訴訟法規定，下列何者非屬當事人應委任律師為訴訟代理人之事件？', '["高等行政法院高等行政訴訟庭管轄之環境保護事件", "適用通常訴訟程序之聲請重新審理事件", "都市計畫審查程序之再審事件", "由具備專利師資格代理之專利行政事件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00112', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於行政程序法之行政程序重新進行之規定，下列敘述何者錯誤？', '["行政機關基於行政處分相對人、利害關係人或第三人之申請，就行政處分所規定之事項，重為審查", "行政程序重新進行之規定，係在一般行政救濟途徑以外，另設之特別救濟途徑", "具有持續效力之行政處分所依據之事實，事後發生有利於利害關係人之變更者，得提起之", "相對人因重大過失而未能在行政程序或救濟程序中主張其事由者，不得適用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00113', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於行政訴訟管轄法院之敘述，下列何者錯誤？', '["關於公務員職務關係之訴訟，得由公務員職務所在地之行政法院管轄", "交通裁決事件，得由原告住所地、居所地、所在地或違規行為地之地方行政法院管轄", "都市計畫訴訟，專屬都市計畫區所在地之地方行政法院管轄", "再審之訴，專屬為判決之原行政法院管轄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00114', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '違法行政處分於法定救濟期間經過後，原處分機關得依職權為全部或一部之撤銷，其撤銷應於下列何項期 間內為之？', '["自原處分機關知有撤銷原因時起2年內", "自撤銷原因發生時起2年內", "自原處分送達受處分人之日起2年內", "自原處分作成之日起2年內"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL)
